#!/usr/bin/env python3
"""
Nuclear reset:
1. Finds oldest clean App.jsx backup
2. Restores it
3. Writes fresh translations.js
4. Verifies App.jsx imports T from translations.js
"""
import os, shutil, re

# ── Find oldest clean backup ──────────────────────────────────────
APP = "src/App.jsx"
BACKUPS = [
    "src/App.jsx.pre-extract",
    "src/App.jsx.pre-optimise", 
    "src/App.jsx.pre-split",
    "src/App.jsx.pre-cleanup",
    "src/App.jsx.backup",
]

restored_from = None
for bak in BACKUPS:
    if os.path.exists(bak):
        size = os.path.getsize(bak)
        print(f"Found backup: {bak} ({size:,} bytes)")
        if size > 100000:  # must be >100KB to be valid
            shutil.copy(bak, APP)
            restored_from = bak
            print(f"✅ Restored App.jsx from {bak}")
            break

if not restored_from:
    print("❌ No valid backup found!")
    exit(1)

# ── Read restored App.jsx ─────────────────────────────────────────
with open(APP, "r", encoding="utf-8") as f:
    app = f.read()

print(f"   App.jsx: {len(app.split(chr(10))):,} lines")

# ── Check if T is inline or already imported ──────────────────────
has_inline_T = bool(re.search(r'\nconst T\s*=\s*\{', app))
has_import_T = "from './data/translations.js'" in app or 'from "./data/translations.js"' in app

print(f"   Inline T: {has_inline_T}")
print(f"   Import T: {has_import_T}")

# ── Write fresh translations.js ───────────────────────────────────
os.makedirs("src/data", exist_ok=True)
TRANS = "src/data/translations.js"

